module.exports = /*#__PURE__*/JSON.parse('{"version":1,"home":{"documentTitle":"Wild Child Fabrications | Hair + Makeup Artistry","metaDescription":"Luxury hair and makeup artistry for bridal, events, media, and creative work.","pageTitle":"HAIR + MAKEUP ARTISTRY","introText":"Luxury beauty experiences with a wild, creative twist. From bridal elegance to avant-garde artistry."},"beauty":{"documentTitle":"Beauty & Events | Pittsburgh, Atlanta | Wild Child Fabrications","metaDescription":"Hair styling and makeup appointments for portraits, events, and special occasions. Rates, location, and travel information.","pageTitle":"Beauty & Events","introText":"Whether you\'re prepping for family portraits, a date night, headshots, a class reunion, a bachelorette celebration—or you simply want fresh tips tailored to your skin—we have a service designed for you.","hairSectionTitle":"Hair Styling + Makeup Appointments","hairItems":["Customized skin prep","High-end makeup application","Custom-fit event lashes","Professional-grade setting sprays & powders","Mini touch-up lipstick kit to-go","Hair styling from simple waves to intricate up-dos","For hair past mid-back, add $25–$50 depending on length."],"locationSectionTitle":"Location & Travel","locationItems":["Sessions take place at artist\'s location unless otherwise arranged.","On-location service is available when our schedule allows.","Travel is billed at $0.70 / mile round-trip plus any parking fees.","Please tell us your hair length and desired style when you book so we can schedule adequate time."],"ratesSectionTitle":"Rates & Booking","ratesTable":[{"service":"Hair & Makeup","price":"$250"},{"service":"Makeup or Hair Only","price":"$125"}],"ratesNotes":["<strong>Retainer:</strong> A $75 non-refundable retainer per service (paid via Venmo) secures your date and is credited to your balance at the appointment.","<strong>Travel:</strong> Quoted at booking."],"cta":{"title":"Ready to look—and feel—your best?","subtitle":"Let\'s create something beautiful together","buttonText":"Contact us to reserve your date"}},"classes":{"documentTitle":"Makeup Classes | Wild Child Fabrications","metaDescription":"Hands-on makeup classes and personal palette profiling. Studio sessions, color analysis, and class logistics.","pageTitle":"Makeup Classes","introText":"Personalized, hands-on instruction—right where you are in your beauty journey.","cards":[{"name":"The Newbie","price":"$275","perfectFor":"Beginners who want a natural, everyday look","details":"3-hour session: Includes a basic 12 swatch color season analysis, skin + makeup consultation, full makeup application with pro kit, step-by-step guidance, customized product list emailed afterward. You do not need to bring anything but yourself for this option!"},{"name":"Makeup Lover","price":"$375","perfectFor":"Those who own plenty of products and want to level up","details":"3.5 hour session: Includes a 36 swatch color season analysis. Bring your makeup bag/brushes; we combine your products with ours, demo half your face, you complete the other with our guidance, product list + recommendations emailed after."},{"name":"Age Appropriate","price":"$300","perfectFor":"Anyone learning age-specific techniques or adapting to changing skin","details":"3-hour session: Includes basic 12 swatch color analysis, skincare review, trend coaching, customized look, product list emailed after. Bring what you own + use of our professional kit."},{"name":"Personal Palette Profiling","price":"See pricing below","perfectFor":"Anyone looking to understand their color season and receive expert guidance on makeup and wardrobe choices that truly complement their unique palette.","details":"","includedItems":["45-minute consultation (per person)","36-color swatch seasonal analysis","Personalized makeup and wardrobe recommendations based on your color profile","Consultation only — no makeup application"],"pricingItems":["Add-on to an existing hair/makeup service: $100","1-Hour Session (standalone): $125","Session for 2: $225 (1.5 hour session for 2 people)","Party Session: $425 (3.5 hour session for 4 people)"],"additionalInfo":"Travel costs may apply when relevant. A 50% retainer is required to book all sessions.","learnMorePath":"/color-palette-party","learnMoreLabel":"Learn More"}],"hourlyAddOnNote":"Hourly add-on: $75 / hour for extended practice or extra looks.","logisticsTitle":"Class Logistics","logisticsItems":["Classes are held at the artist\'s studio","Color palette parties are held at client\'s location","Travel may be arranged; standard travel fees apply.","<strong>Retainer:</strong> A 50% retainer is required to book all sessions. Retainers do not roll over to new dates."],"cta":{"title":"Ready to learn something new?","subtitle":"Let\'s schedule your time with us","buttonText":"Contact us to schedule your class"}},"contact":{"documentTitle":"Contact | Wild Child Fabrications","metaDescription":"Get in touch with Wild Child Fabrications for bridal, events, on-set, classes, and creative makeup bookings.","pageTitle":"Get In Touch","introText":"Ready to create something beautiful together? Fill out the form below and we\'ll get back to you soon!","instagramButtonText":"Follow on Instagram","instagramUrl":"https://www.instagram.com/wildchildfabrications/","venmoButtonText":"Pay with Venmo","venmoUrl":"https://account.venmo.com/u/ChristaleeHMUA","infoPrefix":"You can also","infoLinkText":"email us","infoEmail":"clema.fx@gmail.com","infoMiddleText":", or call us at","infoPhone":"724 766 6364","infoSuffix":"(no texts please)"},"creativeFx":{"documentTitle":"Creative & FX Makeup | Wild Child Fabrications","metaDescription":"Theater, cosplay, TV and film FX, body paint, and custom creative makeup. Booking and pricing information.","pageTitle":"Creative & FX","introText":"With a strong background in special effects, I bring your vision to life through innovative solutions, years of hands-on experience, and a distinctive creative flair. Below is a list of services we offer—but our capabilities are not limited to these alone. If you have a unique idea that doesn\'t quite fit into these categories, I\'d love to hear about it and explore how we can make it happen.","servicesTitle":"Services We Offer","serviceItems":["<strong>Theater - Live Performance</strong> - Living statues, Theater, Comedy, Street Art, etc.","<strong>Personal Event Makeups</strong> - Halloween, Cosplay, Conventions, etc.","<strong>Specialty Makeup for TV/Film</strong> - Aging, Special effects, character design, etc.","<strong>Body & Face Paint</strong> - Photo shoots, nightclub or sporting events, parties for kids or adults, Painted baby bumps, etc.","<strong>Nightclub Events</strong> - Enchant your customers by transforming your staff into something to match your theme for the night."],"pricingTitle":"Pricing Information","pricingItems":["Face painting for parties is a 2 hour minimum booking window for $250 + potential travel fee. $75/hour after two hours.","Full body paint pricing starts at $300."],"bookingTitle":"Booking & Rates","bookingParagraphs":["Each project is unique and may vary in the time, materials, and expertise required to bring your vision to life. Because of this, all jobs are quoted individually, with custom rates tailored to the specific needs of your project.","For any work that involves prosthetics or specialty supplies requiring prep or painting, clients are responsible for purchasing these items in advance with artist\'s guidance. This ensures a smooth and timely makeup application process. We\'ll always provide a clear list of required products along with estimated costs before requesting your order. Please note that we do not pre-order specialty items without upfront payment.","Makeup prep time will be included in your final balance.","To secure your appointment, a retainer is required."]},"faq":{"documentTitle":"FAQ | Wild Child Fabrications","metaDescription":"Answers about business hours, contact preferences, contracts, payments, appointments, prep, studio policies, bridal pricing, and inclusivity.","pageTitle":"Q & A\'s","introText":"Find answers to common questions about our services, booking process, and policies.","items":[{"question":"What are your business hours to get a hold of you?","answerHtml":"For client communication and admin hours, we respond via email or call Monday - Fridays from 10am - 6pm. We unfortunately cannot answer emails during weekends as we are solely focused on creating a great client experience with weddings on weekends. If you call and we do not answer, please leave a voicemail so we can get back to you."},{"question":"How should we get a hold of you?","answerHtml":"Email or our <a href=\\"/book-hair-and-makeup-artist\\" class=\\"faq-link\\">contact form</a> is preferred so that way I can keep track of all your event details in one place and create a seamless beauty experience for you. Calls can be taken during our business hours of M-F 10am to 6pm. Please refrain from texting, Instagram direct messages and Facebook messaging us as it\'s harder for us to keep track and make sure you get a prompt and professional response."},{"question":"How is my contract sent?","answerHtml":"We send all of our contracts via email in a shared Word document. We\'re happy to clarify anything on the contract before it gets completed."},{"question":"How do I pay my retainer and/or booking fees?","answerHtml":"Those can be made via Venmo only. The username is <a href=\\"https://account.venmo.com/u/ChristaleeHMUA\\" target=\\"_blank\\" rel=\\"noopener noreferrer\\" class=\\"faq-link\\">@ChristaleeHMUA</a>. For convenience, we have a link to that on our site! Please do not send retainer/booking payments before discussion with the artist so that we can create a contract for your event date beforehand."},{"question":"Where is my appointment located?","answerHtml":"Unless otherwise discussed at booking, your appointment will take place at artist\'s location. Full location details will be released within 48 hours of your appointment in a detail confirmation email."},{"question":"How should I prep for my appointment?","answerHtml":"Please come with a fresh, completely makeup free face. For hair appointments, your hair must be washed and blown completely dry within 12-15 hours of your appointment. Hair should be \\"lived in\\", but not dirty. This applies to event makeups, trials, weddings, bridal parties, etc. As far as inspiration photos, please narrow down your choices to no more than 1-3 photos per service (1-3 photos for hair or 1-3 for makeup) with a model that has a similar hair/skin color to yours. We will go over these during your consultation included in your appointment time."},{"question":"Can I bring someone to my trial or appointment at your studio?","answerHtml":"Please bring no more than one supportive friend or family member to your appointment. We highly suggest you pick your best hype woman/friend rather than your \\"too honest\\" friend for the best experience. We want you to walk out feeling your best!"},{"question":"Do you have to book us for both hair AND makeup since you offer both?","answerHtml":"You don\'t! You are absolutely welcome to book us for either just hair or just makeup - but we welcome booking both and typically have a team ready to add onto your day - with availability!"},{"question":"Bridal party pricing - hidden fees?","answerHtml":"There are no hidden fees in our pricing. You will see where every dollar is being spent in your outlined contract. Our packages show base pricing which includes only the services themselves - added on to your contract will be fees specifically pertaining to travel, parking, early start time fees for your day where applicable, and an automatic included 20% gratuity."},{"question":"Do you carry insurance?","answerHtml":"Yes, we\'re happy to share more information upon request."},{"question":"What about men, they/them / non-binary or transitioning client needs?","answerHtml":"We are always a safe space to help you bring the vision to life you see for yourself long term or just in the moment. We offer anything from slight grooming/polishing beauty services to full glam looks. Pricing will vary depending on client\'s specific needs and vision. We will always greet you openly and listen to your wants in a desired look."}]}}');

